// MARK: - Secure Analytics & Debugging Module

/// Log categories for structured logging
enum LogCategory: String {
    case authentication = "Auth"
    case network = "Network"
    case userData = "UserData"
    case error = "Error"
    case lifecycle = "Lifecycle"
    case interaction = "Interaction"
}

/// Log level controlling verbosity
enum LogLevel: Int, Comparable {
    case verbose = 0
    case debug = 1
    case info = 2
    case warning = 3
    case error = 4
    case critical = 5

    static func < (lhs: LogLevel, rhs: LogLevel) -> Bool {
        lhs.rawValue < rhs.rawValue
    }

    var label: String {
        switch self {
        case .verbose: return "VERBOSE"
        case .debug: return "DEBUG"
        case .info: return "INFO"
        case .warning: return "WARNING"
        case .error: return "ERROR"
        case .critical: return "CRITICAL"
        }
    }
}

// MARK: - Redaction Utilities

struct SensitiveDataRedactor {

    /// Redacts an email to show only domain hint: "j***@e***.com"
    static func redactEmail(_ email: String?) -> String {
        guard let email = email, let atIndex = email.firstIndex(of: "@") else {
            return "<redacted-email>"
        }
        let local = email[email.startIndex..<atIndex]
        let domain = email[email.index(after: atIndex)...]
        let redactedLocal = local.isEmpty ? "*" : "\(local.first!)***"
        let redactedDomain: String
        if let dotIndex = domain.firstIndex(of: ".") {
            let domainName = domain[domain.startIndex..<dotIndex]
            let tld = domain[dotIndex...]
            redactedDomain = domainName.isEmpty ? "***\(tld)" : "\(domainName.first!)***\(tld)"
        } else {
            redactedDomain = "***"
        }
        return "\(redactedLocal)@\(redactedDomain)"
    }

    /// Redacts a user ID to show only last 4 characters
    static func redactUserID(_ userID: String?) -> String {
        guard let userID = userID, userID.count > 4 else {
            return "<redacted-id>"
        }
        let suffix = userID.suffix(4)
        return "***\(suffix)"
    }

    /// Fully redacts tokens — never log token values
    static func redactToken(_ token: String?) -> String {
        guard let token = token, !token.isEmpty else {
            return "<no-token>"
        }
        return "<token-present, length:\(token.count)>"
    }

    /// Redacts sensitive keys from a dictionary payload
    static func redactPayload(_ payload: [String: Any]?) -> [String: Any] {
        guard let payload = payload else { return [:] }

        let sensitiveKeys: Set<String> = [
            "password", "token", "access_token", "refresh_token",
            "authorization", "secret", "api_key", "apiKey",
            "credit_card", "creditCard", "card_number", "cardNumber",
            "cvv", "ssn", "social_security", "pin",
            "session_token", "sessionToken", "cookie",
            "private_key", "privateKey"
        ]

        let piiKeys: Set<String> = [
            "email", "phone", "phone_number", "phoneNumber",
            "address", "date_of_birth", "dateOfBirth", "dob",
            "first_name", "firstName", "last_name", "lastName",
            "full_name", "fullName", "name"
        ]

        var redacted = [String: Any]()
        for (key, value) in payload {
            let lowerKey = key.lowercased()
            if sensitiveKeys.contains(lowerKey) {
                redacted[key] = "<REDACTED>"
            } else if piiKeys.contains(lowerKey) {
                if let stringValue = value as? String, stringValue.contains("@") {
                    redacted[key] = redactEmail(stringValue)
                } else {
                    redacted[key] = "<PII-REDACTED>"
                }
            } else if let nestedDict = value as? [String: Any] {
                redacted[key] = redactPayload(nestedDict)
            } else {
                redacted[key] = value
            }
        }
        return redacted
    }

    /// Redacts URL query parameters that may contain sensitive data
    static func redactURL(_ url: URL?) -> String {
        guard let url = url else { return "<no-url>" }
        guard var components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            return "\(url.scheme ?? "")://\(url.host ?? "")\(url.path)"
        }

        let sensitiveParams: Set<String> = [
            "token", "access_token", "refresh_token", "api_key",
            "apiKey", "secret", "password", "session", "key", "code"
        ]

        components.queryItems = components.queryItems?.map { item in
            if sensitiveParams.contains(item.name.lowercased()) {
                return URLQueryItem(name: item.name, value: "<REDACTED>")
            }
            return item
        }

        // Remove host internals in production — only show path
        #if !DEBUG
        return "\(url.path)?\(components.query ?? "")"
        #else
        return components.string ?? url.path
        #endif
    }

    /// Redacts HTTP headers
    static func redactHeaders(_ headers: [String: String]?) -> [String: String] {
        guard let headers = headers else { return [:] }
        let sensitiveHeaders: Set<String> = [
            "authorization", "cookie", "set-cookie",
            "x-api-key", "x-auth-token", "proxy-authorization"
        ]
        var redacted = [String: String]()
        for (key, value) in headers {
            if sensitiveHeaders.contains(key.lowercased()) {
                redacted[key] = "<REDACTED, length:\(value.count)>"
            } else {
                redacted[key] = value
            }
        }
        return redacted
    }
}

// MARK: - Analytics Event

struct AnalyticsEvent {
    let timestamp: Date
    let category: LogCategory
    let level: LogLevel
    let eventName: String
    let metadata: [String: Any]

    init(category: LogCategory, level: LogLevel, eventName: String, metadata: [String: Any] = [:]) {
        self.timestamp = Date()
        self.category = category
        self.level = level
        self.eventName = eventName
        // Always redact metadata before storing
        self.metadata = SensitiveDataRedactor.redactPayload(metadata)
    }
}

// MARK: - Secure Logger

final class SecureLogger {

    static let shared = SecureLogger()

    /// Minimum log level for production. In DEBUG, everything is logged.
    /// In RELEASE, only .warning and above.
    private var minimumLevel: LogLevel

    private let osLog = OSLog(subsystem: Bundle.main.bundleIdentifier ?? "com.app.analytics", category: "Analytics")

    private let queue = DispatchQueue(label: "com.app.securelogger", qos: .utility)

    /// In-memory ring buffer of recent events (redacted) for crash diagnostics
    private var eventBuffer: [AnalyticsEvent] = []
    private let maxBufferSize = 200

    private init() {
        #if DEBUG
        self.minimumLevel = .verbose
        #else
        self.minimumLevel = .warning
        #endif
    }

    /// Configure minimum log level at runtime (e.g., from remote config)
    func setMinimumLevel(_ level: LogLevel) {
        queue.sync { self.minimumLevel = level }
    }

    // MARK: - Core Logging

    private func log(category: LogCategory, level: LogLevel, message: String, metadata: [String: Any] = [:], file: String = #file, function: String = #function, line: Int = #line) {

        guard level >= minimumLevel else { return }

        let event = AnalyticsEvent(category: category, level: level, eventName: message, metadata: metadata)

        queue.async { [weak self] in
            self?.bufferEvent(event)
        }

        let fileName = (file as NSString).lastPathComponent
        let logString = "[\(level.label)][\(category.rawValue)] \(message) | \(fileName):\(line)"

        // Use os_log for structured logging — it automatically redacts in production
        switch level {
        case .verbose, .debug:
            os_log(.debug, log: osLog, "%{public}s", logString)
        case .info:
            os_log(.info, log: osLog, "%{public}s", logString)
        case .warning:
            os_log(.default, log: osLog, "%{public}s", logString)
        case .error, .critical:
            os_log(.error, log: osLog, "%{public}s", logString)
        }

        // Only use print/NSLog in DEBUG builds
        #if DEBUG
        let metadataString = metadata.isEmpty ? "" : " | metadata: \(SensitiveDataRedactor.redactPayload(metadata))"
        print("📊 \(logString)\(metadataString)")
        #endif
    }

    private func bufferEvent(_ event: AnalyticsEvent) {
        eventBuffer.append(event)
        if eventBuffer.count > maxBufferSize {
            eventBuffer.removeFirst(eventBuffer.count - maxBufferSize)
        }
    }

    /// Export buffered events for crash report attachment (all data already redacted)
    func exportBufferedEvents() -> [[String: Any]] {
        return queue.sync {
            let formatter = ISO8601DateFormatter()
            return eventBuffer.map { event in
                [
                    "timestamp": formatter.string(from: event.timestamp),
                    "category": event.category.rawValue,
                    "level": event.level.label,
                    "event": event.eventName,
                    "metadata": event.metadata
                ]
            }
        }
    }

    // MARK: - Authentication Flow Tracking

    func trackAuthAttempt(method: String, userIdentifierHint: String?) {
        let redactedHint: String
        if let hint = userIdentifierHint {
            if hint.contains("@") {
                redactedHint = SensitiveDataRedactor.redactEmail(hint)
            } else {
                redactedHint = SensitiveDataRedactor.redactUserID(hint)
            }
        } else {
            redactedHint = "<none>"
        }

        log(category: .authentication, level: .info,
            message: "Auth attempt started",
            metadata: [
                "method": method,
                "identifier_hint": redactedHint
            ])
    }

    func trackAuthSuccess(userID: String) {
        log(category: .authentication, level: .info,
            message: "Auth succeeded",
            metadata: [
                "user_id_hint": SensitiveDataRedactor.redactUserID(userID)
            ])
    }

    func trackAuthFailure(reason: String, statusCode: Int? = nil) {
        // Never log the actual credentials or detailed server error messages
        // that might reveal internal implementation
        let safeReason: String
        switch reason.lowercased() {
        case let r where r.contains("invalid password"):
            safeReason = "invalid_credentials"
        case let r where r.contains("not found"):
            safeReason = "account_not_found"
        case let r where r.contains("locked"):
            safeReason = "account_locked"
        case let r where r.contains("expired"):
            safeReason = "session_expired"
        default:
            safeReason = "auth_failure"
        }

        var metadata: [String: Any] = ["reason": safeReason]
        if let code = statusCode {
            metadata["status_code"] = code
        }

        log(category: .authentication, level: .warning,
            message: "Auth failed",
            metadata: metadata)
    }

    func trackTokenRefresh(success: Bool) {
        log(category: .authentication, level: .info,
            message: "Token refresh \(success ? "succeeded" : "failed")",
            metadata: ["success": success])
    }

    func trackLogout(userID: String?, reason: String) {
        log(category: .authentication, level: .info,
            message: "User logged out",
            metadata: [
                "user_id_hint": SensitiveDataRedactor.redactUserID(userID),
                "reason": reason
            ])
    }

    // MARK: - API Call Tracking

    func trackAPIRequest(method: String, url: URL?, requestID: String? = nil) {
        var metadata: [String: Any] = [
            "http_method": method,
            "path": SensitiveDataRedactor.redactURL(url)
        ]
        if let requestID = requestID {
            metadata["request_id"] = requestID
        }

        log(category: .network, level: .debug,
            message: "API request",
            metadata: metadata)
    }

    func trackAPIResponse(method: String, url: URL?, statusCode: Int, duration: TimeInterval, requestID: String? = nil) {
        var metadata: [String: Any] = [
            "http_method": method,
            "path": SensitiveDataRedactor.redactURL(url),
            "status_code": statusCode,
            "duration_ms": Int(duration * 1000)
        ]
        if let requestID = requestID {
            metadata["request_id"] = requestID
        }

        let level: LogLevel = statusCode >= 400 ? .warning : .debug

        log(category: .network, level: level,
            message: "API response",
            metadata: metadata)
    }

    func trackAPIError(method: String, url: URL?, error: Error, requestID: String? = nil) {
        let nsError = error as NSError

        // Only log error domain and code, not the full localized description
        // which may contain server-side details or internal paths
        var metadata: [String: Any] = [
            "http_method": method,
            "path": SensitiveDataRedactor.redactURL(url),
            "error_domain": nsError.domain,
            "error_code": nsError.code
        ]
        if let requestID = requestID {
            metadata["request_id"] = requestID
        }

        log(category: .network, level: .error,
            message: "API error",
            metadata: metadata)
    }

    // MARK: - User Data Change Tracking

    func trackUserDataChange(userID: String?, changeType: String, fieldNames: [String]) {
        // Log WHICH fields changed, never the values
        let safeFields = fieldNames.map { field -> String in
            // Don't reveal internal field naming conventions in production
            #if DEBUG
            return field
            #else
            return field.prefix(20).description
            #endif
        }

        log(category: .userData, level: .info,
            message: "User data changed",
            metadata: [
                "user_id_hint": SensitiveDataRedactor.redactUserID(userID),
                "change_type": changeType,
                "fields_changed": safeFields,
                "field_count": fieldNames.count
            ])
    }

    // MARK: - User Interaction Tracking

    func trackScreenView(screenName: String) {
        log(category: .interaction, level: .info,
            message: "Screen viewed",
            metadata: ["screen": screenName])
    }

    func trackButtonTap(buttonName: String, screenName: String) {
        log(category: .interaction, level: .debug,
            message: "Button tapped",
            metadata: [
                "button": buttonName,
                "screen": screenName
            ])
    }

    func trackUserAction(action: String, context: [String: Any] = [:]) {
        // Redact any sensitive data that might be in context
        log(category: .interaction, level: .info,
            message: "User action: \(action)",
            metadata: SensitiveDataRedactor.redactPayload(context))
    }

    // MARK: - Error Tracking

    func trackError(_ error: Error, context: String, userID: String? = nil, additionalInfo: [String: Any] = [:]) {
        let nsError = error as NSError

        var metadata: [String: Any] = [
            "context": context,
            "error_domain": nsError.domain,
            "error_code": nsError.code
        ]

        if let userID = userID {
            metadata["user_id_hint"] = SensitiveDataRedactor.redactUserID(userID)
        }

        // Merge additional info but redact it
        let redactedInfo = SensitiveDataRedactor.redactPayload(additionalInfo)
        for (key, value) in redactedInfo {
            metadata[key] = value
        }

        // In debug, include localized description; in release, omit it
        // as it may contain internal details
        #if DEBUG
        metadata["description"] = nsError.localizedDescription
        #endif

        log(category: .error, level: .error,
            message: "Error occurred",
            metadata: metadata)
    }

    func trackCriticalError(_ error: Error, context: String) {
        let nsError = error as NSError
        log(category: .error, level: .critical,
            message: "CRITICAL: \(context)",
            metadata: [
                "error_domain": nsError.domain,
                "error_code": nsError.code
            ])
    }

    // MARK: - App Lifecycle

    func trackAppLaunch(isFirstLaunch: Bool) {
        log(category: .lifecycle, level: .info,
            message: "App launched",
            metadata: [
                "first_launch": isFirstLaunch,
                "os_version": ProcessInfo.processInfo.operatingSystemVersionString,
                "app_version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "unknown"
            ])
    }

    func trackAppBackground() {
        log(category: .lifecycle, level: .info, message: "App entered background")
    }

    func trackAppForeground() {
        log(category: .lifecycle, level: .info, message: "App entered foreground")
    }
}

// MARK: - Network Interceptor (URLProtocol-based logging)

final class AnalyticsURLProtocol: URLProtocol {

    private static let handledKey = "com.app.analytics.handled"

    override class func canInit(with request: URLRequest) -> Bool {
        // Only intercept if not already handled
        guard URLProtocol.property(forKey: handledKey, in: request) == nil else {
            return false
        }
        return true
    }

    override class func canonicalRequest(for request: URLRequest) -> URLRequest {
        return request
    }

    override func startLoading() {
        let logger = SecureLogger.shared
        let startTime = CFAbsoluteTimeGetCurrent()
        let requestID = UUID().uuidString.prefix(8).description

        // Log request — redact headers and URL
        logger.trackAPIRequest(
            method: request.httpMethod ?? "UNKNOWN",
            url: request.url,
            requestID: requestID
        )

        // Log redacted headers in debug only
        #if DEBUG
        let redactedHeaders = SensitiveDataRedactor.redactHeaders(
            request.allHTTPHeaderFields
        )
        if !redactedHeaders.isEmpty {
            // This only prints in debug builds
            print("📊 [DEBUG][Network] Request headers (redacted): \(redactedHeaders)")
        }
        #endif

        // Mark as handled and forward
        guard let mutableRequest = (request as NSURLRequest).mutableCopy() as? NSMutableURLRequest else {
            client?.urlProtocol(self, didFailWithError: NSError(domain: "AnalyticsURLProtocol", code: -1))
            return
        }
        URLProtocol.setProperty(true, forKey: AnalyticsURLProtocol.handledKey, in: mutableRequest)

        let session = URLSession(configuration: .default, delegate: nil, delegateQueue: nil)
        let task = session.dataTask(with: mutableRequest as URLRequest) { [weak self] data, response, error in
            guard let self = self else { return }

            let duration = CFAbsoluteTimeGetCurrent() - startTime

            if let httpResponse = response as? HTTPURLResponse {
                logger.trackAPIResponse(
                    method: self.request.httpMethod ?? "UNKNOWN",
                    url: self.request.url,
                    statusCode: httpResponse.statusCode,
                    duration: duration,
                    requestID: requestID
                )

                self.client?.urlProtocol(self, didReceive: httpResponse, cacheStoragePolicy: .notAllowed)
            }

            if let error = error {
                logger.trackAPIError(
                    method: self.request.httpMethod ?? "UNKNOWN",
                    url: self.request.url,
                    error: error,
                    requestID: requestID
                )
                self.client?.urlProtocol(self, didFailWithError: error)
                return
            }

            if let data = data {
                // Never log response body — it may contain sensitive user data
                // Only log the size for debugging
                #if DEBUG
                print("📊 [DEBUG][Network] Response body size: \(data.count) bytes for \(requestID)")
                #endif

                self.client?.urlProtocol(self, didLoad: data)
            }

            self.client?.urlProtocolDidFinishLoading(self)
        }
        task.resume()
    }

    override func stopLoading() {
        // No-op
    }
}

// MARK: - Safe Error Presentation (User-Facing)

struct SafeErrorPresenter {

    /// Returns a user-safe error message that doesn't leak internals
    static func userFacingMessage(for error: Error, context: String) -> String {
        // Log the full error internally (redacted)
        SecureLogger.shared.trackError(error, context: context)

        // Return generic user-facing message
        let nsError = error as NSError

        switch nsError.domain {
        case NSURLErrorDomain:
            switch nsError.code {
            case NSURLErrorNotConnectedToInternet:
                return "Please check your internet connection and try again."
            case NSURLErrorTimedOut:
                return "The request timed out. Please try again."
            default:
                return "A network error occurred. Please try again later."
            }
        default:
            return "Something went wrong. Please try again. If the problem persists, contact support."
        }
    }
}

